import requests

def main(inputs, storages):
    item_ref = inputs.get('FETCH_HN_STORIES') or {}
    sid = item_ref.get('id')
    if not sid:
        return {'output': None}
    item = requests.get(
        f'https://hacker-news.firebaseio.com/v0/item/{sid}.json',
        timeout=15
    ).json() or {}
    comments = []
    for cid in (item.get('kids') or [])[:3]:
        c = requests.get(
            f'https://hacker-news.firebaseio.com/v0/item/{cid}.json',
            timeout=15
        ).json() or {}
        text = (c.get('text') or '')[:400]
        if text:
            comments.append({'by': c.get('by', ''), 'text': text})
    return {
        'output': {
            'id': sid,
            'title': item.get('title', ''),
            'url': item.get('url') or f'https://news.ycombinator.com/item?id={sid}',
            'score': item.get('score', 0),
            'descendants': item.get('descendants', 0),
            'comments': comments,
        }
    }

